```tsx
function DateDisplay() {
  const { getFormattedDate, timezone, changeTimezone } = useTimezone()

  const now = new Date()

  return (
    <div>
      <p>Current timezone: {timezone}</p>
      <p>Formatted: {getFormattedDate(now)}</p>
      <button onClick={() => changeTimezone('America/New_York')}>
        Switch to NY Time
      </button>
    </div>
  )
}
```

